def alto_clarinet_to_concert(written_note):
    # Maps written note to concert pitch (E♭ alto clarinet)
    note_map = {
        'G': 'E♭', 'G#': 'E', 'A': 'F', 'A#': 'F#', 'B': 'G',
        'C': 'A♭', 'C#': 'A', 'D': 'B♭', 'D#': 'B', 'E': 'C',
        'F': 'D♭', 'F#': 'D', 'G5': 'A♭4'
    }
    return note_map.get(written_note, 'Unknown note')

Example usage: `alto_clarinet_to_concert('C')` returns `'A♭'`.
